1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type Incident = { cause: string; damages: Damage[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	
15	export type QuoteResult = { premium: number };
16	export type ClaimResult = { payout: number; remainingCap: number };
17	export type StepResult = QuoteResult | ClaimResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_SURCHARGE = 0.1;
22	
23	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	};
27	
28	const itemBasePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
29	
30	const quotePremium = (step: QuoteStep): number => {
31	  const baseTotal = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
32	  const withFirstInsurance = baseTotal + baseTotal * FIRST_INSURANCE_SURCHARGE;
33	  return Math.ceil(withFirstInsurance - 1e-9) + PROCESSING_FEE;
34	};
35	
36	export const runScenario = (scenario: Scenario): ScenarioResult => {
37	  const results = scenario.steps.map((step) => {
38	    if (step.op === "quote") return { premium: quotePremium(step) };
39	    return { payout: 0, remainingCap: 0 };
40	  });
41	  return { results };
42	};
